<template>
  <div class="tool-page">
    <ToolGrid title="免费工具" :tools="freeTools" @tool-click="handleTool" />
    <ToolGrid title="会员工具" tag="VIP" :tools="memberTools" :isMember="isMember" style="margin-top: 12px" @tool-click="handleTool" />
    <!-- <ToolGrid title="AI工具" tag="RUG币" :tools="aiTools" style="margin-top: 12px" @tool-click="handleTool" /> -->

    <!-- 进度条（批量操作） -->
    <el-dialog title="处理中..." :visible.sync="progress.visible" width="360px" :close-on-click-modal="false" :show-close="false">
      <div style="padding: 8px 0">
        <el-progress :percentage="progressPercent" status="striped" :striped="true" :striped-flow="true" />
        <div style="margin-top: 10px; color: #ccc; font-size: 13px; text-align: center">{{ progress.current }} / {{ progress.total }}</div>
      </div>
    </el-dialog>

    <!-- 清除水印引导弹窗 -->
    <el-dialog title="清除水印" :visible.sync="removeWatermarkDialog.visible" width="320px" :close-on-click-modal="false">
      <div class="remove-wm-body">
        <template v-if="removeWatermarkDialog.step === 1">
          <div class="remove-wm-step">
            <div class="remove-wm-step-num">1</div>
            <div class="remove-wm-step-text">在 PS 中用<strong>套索（L）</strong>圈选水印区域</div>
          </div>
          <div class="remove-wm-step">
            <div class="remove-wm-step-num">2</div>
            <div class="remove-wm-step-text">圈选完成后，回到插件点击"执行清除"</div>
          </div>
          <div class="remove-wm-tip">
            <i class="el-icon-info-outline"></i>
            尽量贴近水印边缘圈选，背景越简单效果越好
          </div>
          <el-button type="primary" style="width: 100%; margin-top: 16px" size="small" @click="doRemoveWatermark"> 我已圈选，执行清除 </el-button>
        </template>
        <template v-else>
          <div class="remove-wm-waiting">
            <i class="el-icon-loading remove-wm-icon"></i>
            <p>正在清除水印...</p>
          </div>
        </template>
      </div>
    </el-dialog>

    <!-- 添加水印对话框 -->
    <el-dialog title="添加水印" :visible.sync="watermarkDialog.visible" width="320px" @close="resetWatermarkDialog">
      <div class="watermark-body">
        <div class="watermark-field-label">水印文字</div>
        <el-input v-model="watermarkDialog.text" placeholder="请输入水印文字" clearable />
        <div class="watermark-field-label" style="margin-top: 14px">水印位置</div>
        <div class="watermark-position-grid">
          <div
            v-for="pos in watermarkPositions"
            :key="pos.value"
            class="watermark-pos-btn"
            :class="{ 'watermark-pos-btn--active': watermarkDialog.position === pos.value }"
            @click="watermarkDialog.position = pos.value"
          >
            <i :class="pos.icon"></i>
            <span>{{ pos.label }}</span>
          </div>
        </div>
      </div>
      <span slot="footer">
        <el-button size="small" @click="watermarkDialog.visible = false">取消</el-button>
        <el-button size="small" type="primary" @click="confirmAddWatermark">确认</el-button>
      </span>
    </el-dialog>

    <!-- 尺寸规范化对话框 -->
    <el-dialog title="尺寸规范化" :visible.sync="resizeDialog.visible" width="340px" @close="resetResizeDialog">
      <div class="resize-body">
        <p class="resize-section-label">常用比例</p>
        <div class="resize-presets">
          <div
            v-for="p in resizePresets"
            :key="p.label"
            class="resize-preset-btn"
            :class="{ 'resize-preset-btn--active': resizeDialog.activePreset === p.label }"
            @click="applyResizePreset(p)"
          >
            <div class="preset-ratio-box" :style="{ width: p.boxW + 'px', height: p.boxH + 'px' }"></div>
            <span>{{ p.label }}</span>
          </div>
        </div>
        <p class="resize-section-label" style="margin-top: 14px">自定义尺寸</p>
        <div class="resize-inputs">
          <div class="resize-input-row">
            <span class="resize-input-label">宽</span>
            <el-input v-model="resizeDialog.width" placeholder="留空等比计算" size="small" clearable @input="resizeDialog.activePreset = ''">
              <template slot="append">px</template>
            </el-input>
          </div>
          <div class="resize-input-row">
            <span class="resize-input-label">高</span>
            <el-input v-model="resizeDialog.height" placeholder="留空等比计算" size="small" clearable @input="resizeDialog.activePreset = ''">
              <template slot="append">px</template>
            </el-input>
          </div>
        </div>
        <p class="resize-hint">两项均填则强制调整，留空一项则等比缩放</p>
      </div>
      <span slot="footer">
        <el-button size="small" @click="resizeDialog.visible = false">取消</el-button>
        <el-button size="small" type="primary" @click="confirmResize">确认</el-button>
      </span>
    </el-dialog>

    <!-- 画布旋转对话框 -->
    <el-dialog title="画布旋转" :visible.sync="rotateDialog.visible" width="300px" @close="resetRotateDialog" custom-class="rotate-dialog">
      <div class="rotate-body">
        <p class="rotate-label">选择旋转角度</p>
        <div class="rotate-grid">
          <div
            v-for="opt in rotateOptions"
            :key="opt.value"
            class="rotate-btn"
            :class="{ 'rotate-btn--active': rotateDialog.preset === opt.value }"
            @click="rotateDialog.preset = opt.value"
          >
            <i :class="opt.icon" class="rotate-btn-icon"></i>
            <span>{{ opt.label }}</span>
          </div>
        </div>
        <transition name="fade-slide">
          <div v-if="rotateDialog.preset === 'custom'" class="rotate-custom">
            <span class="rotate-custom-label">自定义角度</span>
            <el-input v-model="rotateDialog.customAngle" placeholder="-360 ~ 360" size="small" class="rotate-custom-input">
              <template slot="append">°</template>
            </el-input>
          </div>
        </transition>
      </div>
      <span slot="footer" class="rotate-footer">
        <el-button size="small" @click="rotateDialog.visible = false">取消</el-button>
        <el-button size="small" type="primary" @click="confirmRotate">确认旋转</el-button>
      </span>
    </el-dialog>

    <!-- 批量导出图包对话框 -->
    <el-dialog title="批量导出图包" :visible.sync="exportDialog.visible" width="400px" @close="resetExportDialog">
      <el-form label-width="90px" @submit.native.prevent>
        <el-form-item label="源文件夹">
          <el-input v-model="exportDialog.srcFolder" placeholder="点击选择" readonly>
            <el-button slot="append" icon="el-icon-folder-opened" @click="selectExportSrcFolder" />
          </el-input>
        </el-form-item>
        <el-form-item label="目标文件夹">
          <el-input v-model="exportDialog.destFolder" placeholder="点击选择" readonly>
            <el-button slot="append" icon="el-icon-folder-opened" @click="selectExportDestFolder" />
          </el-input>
        </el-form-item>
        <el-form-item label="导出尺寸">
          <el-input v-model="exportDialog.sizesStr" placeholder="如：800,1500,2000" />
          <div style="font-size: 11px; color: #999; margin-top: 4px">多个尺寸用英文逗号分隔</div>
        </el-form-item>
      </el-form>
      <span slot="footer">
        <el-button @click="exportDialog.visible = false">取消</el-button>
        <el-button type="primary" @click="confirmBatchExport">开始导出</el-button>
      </span>
    </el-dialog>

    <!-- 批量重命名对话框 -->
    <el-dialog title="批量智能重命名" :visible.sync="renameDialog.visible" width="340px" @close="resetRenameDialog">
      <el-form label-width="70px" @submit.native.prevent>
        <el-form-item label="文件夹">
          <el-input v-model="renameDialog.folder" placeholder="点击选择" readonly size="small">
            <el-button slot="append" icon="el-icon-folder-opened" @click="selectRenameFolder" />
          </el-input>
        </el-form-item>
        <el-form-item label="前缀">
          <el-input v-model="renameDialog.prefix" placeholder="可留空" clearable size="small" />
        </el-form-item>
        <el-form-item label="后缀">
          <el-input v-model="renameDialog.suffix" placeholder="可留空" clearable size="small" />
        </el-form-item>
        <el-form-item label="起始序号">
          <el-input-number v-model="renameDialog.startIndex" :min="1" :step="1" size="small" class="rename-index-input" />
        </el-form-item>
        <el-form-item v-if="renameDialog.preview.length" label="预览">
          <div class="rename-preview">
            <div v-for="(item, i) in renameDialog.preview.slice(0, 5)" :key="i" class="rename-preview-row">
              <span class="old-name">{{ item.old }}</span>
              <i class="el-icon-right" style="margin: 0 6px; color: #555" />
              <span class="new-name">{{ item.newName }}</span>
            </div>
            <div v-if="renameDialog.preview.length > 5" style="color: #555; font-size: 11px">...共 {{ renameDialog.preview.length }} 个文件</div>
          </div>
        </el-form-item>
      </el-form>
      <span slot="footer">
        <el-button size="small" @click="renameDialog.visible = false">取消</el-button>
        <el-button size="small" @click="previewRename">预览</el-button>
        <el-button size="small" type="primary" :disabled="!renameDialog.preview.length" @click="confirmBatchRename">执行重命名</el-button>
      </span>
    </el-dialog>

    <!-- 一键样机替换对话框 -->
    <el-dialog title="一键样机替换" :visible.sync="mockupDialog.visible" width="400px" @close="resetMockupDialog">
      <el-form label-width="90px" @submit.native.prevent>
        <el-form-item label="样机文件夹">
          <el-input v-model="mockupDialog.psdFolder" placeholder="点击选择" readonly>
            <el-button slot="append" icon="el-icon-folder-opened" @click="selectMockupPsdFolder" />
          </el-input>
        </el-form-item>
        <el-form-item label="素材文件夹">
          <el-input v-model="mockupDialog.materialFolder" placeholder="点击选择" readonly>
            <el-button slot="append" icon="el-icon-folder-opened" @click="selectMockupMaterialFolder" />
          </el-input>
        </el-form-item>
        <el-form-item label="输出文件夹">
          <el-input v-model="mockupDialog.outputFolder" placeholder="点击选择" readonly>
            <el-button slot="append" icon="el-icon-folder-opened" @click="selectMockupOutputFolder" />
          </el-input>
        </el-form-item>
      </el-form>
      <span slot="footer">
        <el-button @click="mockupDialog.visible = false">取消</el-button>
        <el-button type="primary" @click="confirmMockupReplace">开始处理</el-button>
      </span>
    </el-dialog>
  </div>
</template>

<script>
import ToolGrid from '@/components/ToolGrid.vue';
import * as cepInterface from 'cep-interface';
import { selectFolderDialog } from '@/utils/cepInterface';

const fs = window.require('fs');
const path = window.require('path');

export default {
  name: 'Tool',
  components: { ToolGrid },
  props: {
    userInfo: { type: Object, default: () => ({}) }
  },
  computed: {
    isMember() {
      return !!(this.userInfo && this.userInfo.vipFlag);
    },
    progressPercent() {
      if (!this.progress.total) return 0;
      return Math.round((this.progress.current / this.progress.total) * 100);
    }
  },
  data() {
    return {
      freeTools: [
        { id: 6, name: '图片高清', icon: 'el-icon-zoom-in' },
        { id: 1, name: '清除水印', icon: 'el-icon-magic-stick' },
        { id: 2, name: '添加水印', icon: 'el-icon-edit' },
        { id: 3, name: '一键转 JPG', icon: 'el-icon-refresh' },
        { id: 4, name: '尺寸规范化', icon: 'el-icon-full-screen' },
        { id: 5, name: '画布旋转', icon: 'el-icon-refresh-right' }
      ],
      memberTools: [
        { id: 101, name: '一键样机替换', icon: 'el-icon-copy-document' },
        { id: 102, name: '批量导出图包', icon: 'el-icon-box' },
        { id: 103, name: '批量智能重命名', icon: 'el-icon-document' }
        // { id: 104, name: '光影自动匹配', icon: 'el-icon-sunny' }
      ],
      aiTools: [
        //{ id: 1006, name: '图片高清', icon: 'el-icon-zoom-in' },
        //{ id: 1001, name: '清除水印', icon: 'el-icon-magic-stick' }
      ],
      progress: { visible: false, current: 0, total: 0, errors: [] },
      removeWatermarkDialog: { visible: false, step: 1 },
      watermarkDialog: { visible: false, text: '', position: 'bottom-right' },
      watermarkPositions: [
        { value: 'top-left', label: '左上角', icon: 'el-icon-top-left' },
        { value: 'top-right', label: '右上角', icon: 'el-icon-top-right' },
        { value: 'bottom-left', label: '左下角', icon: 'el-icon-bottom-left' },
        { value: 'bottom-right', label: '右下角', icon: 'el-icon-bottom-right' }
      ],
      resizeDialog: { visible: false, width: '', height: '', activePreset: '' },
      resizePresets: [
        { label: '1:1', w: 2000, h: 2000, boxW: 22, boxH: 22 },
        { label: '4:3', w: 2000, h: 1500, boxW: 24, boxH: 18 },
        { label: '3:4', w: 1500, h: 2000, boxW: 18, boxH: 24 },
        { label: '16:9', w: 1920, h: 1080, boxW: 28, boxH: 16 },
        { label: '9:16', w: 1080, h: 1920, boxW: 16, boxH: 28 }
      ],
      rotateDialog: { visible: false, preset: '90', customAngle: '' },
      rotateOptions: [
        { value: '90', label: '90°', icon: 'el-icon-refresh-right' },
        { value: '180', label: '180°', icon: 'el-icon-refresh' },
        { value: '270', label: '270°', icon: 'el-icon-refresh-left' },
        { value: 'custom', label: '自定义', icon: 'el-icon-edit' }
      ],
      exportDialog: { visible: false, srcFolder: '', destFolder: '', sizesStr: '800,1500,2000' },
      renameDialog: { visible: false, folder: '', prefix: '', suffix: '', startIndex: 1, preview: [], files: [] },
      mockupDialog: { visible: false, psdFolder: '', materialFolder: '', outputFolder: '' }
    };
  },
  methods: {
    // ── 纯函数 ──────────────────────────────────────────────
    calcProportionalSize(origW, origH, inputW, inputH) {
      if (inputW && !inputH) return { w: inputW, h: Math.round((origH * inputW) / origW) };
      if (inputH && !inputW) return { w: Math.round((origW * inputH) / origH), h: inputH };
      return { w: inputW, h: inputH };
    },
    buildExportFileName(baseName, size) {
      return `${baseName}_${size}px.png`;
    },
    buildRenameFileName(prefix, index, suffix, ext) {
      return `${prefix}${index}${suffix}${ext}`;
    },
    parseJsxResult(result) {
      if (result === 'true' || result === true) return { ok: true };
      const msg = String(result).startsWith('false:') ? String(result).slice(6) : String(result);
      return { ok: false, msg };
    },

    // ── 权限检查 ─────────────────────────────────────────────
    checkMember() {
      // if (!this.isMember) {
      //   this.$emit('handleRecharge');
      //   return false;
      // }
      return true;
    },

    // ── 工具分发 ─────────────────────────────────────────────
    handleTool(item) {
      const handlerMap = {
        1: this.handleRemoveWatermark,
        2: this.handleAddWatermark,
        3: this.handleSaveAsJpg,
        4: this.handleResizeDocument,
        5: this.handleRotateCanvas,
        6: this.handleEnhanceImage,
        101: this.handleMockupReplace,
        102: this.handleBatchExport,
        103: this.handleBatchRename,
        104: this.handleLightingMatch
      };
      const handler = handlerMap[item.id];
      if (handler) handler.call(this);
    },

    // ── 工具 1：清除水印 ──────────────────────────────────────
    handleRemoveWatermark() {
      this.removeWatermarkDialog.step = 1;
      this.removeWatermarkDialog.visible = true;
    },
    async startSelectWatermark() {
      // 已移除自动切换工具，避免 PS 属性面板弹出覆盖插件
    },
    async doRemoveWatermark() {
      const result = await cepInterface.evalExtendscript('removeWatermark()');
      const { ok, msg } = this.parseJsxResult(result);
      this.removeWatermarkDialog.visible = false;
      this.removeWatermarkDialog.step = 1;
      if (ok) {
        this.$message.success('水印已清除');
      } else {
        this.$message.warning(msg);
      }
    },

    // ── 工具 2：添加水印 ──────────────────────────────────────
    handleAddWatermark() {
      this.watermarkDialog.visible = true;
    },
    resetWatermarkDialog() {
      this.watermarkDialog.text = '';
      this.watermarkDialog.position = 'bottom-right';
    },
    async confirmAddWatermark() {
      const text = this.watermarkDialog.text.trim();
      if (!text) {
        this.$message.warning('水印文字不能为空');
        return;
      }
      this.watermarkDialog.visible = false;
      const result = await cepInterface.evalExtendscript(`addWatermarkText("${encodeURIComponent(text)}", "${this.watermarkDialog.position}")`);
      const { ok, msg } = this.parseJsxResult(result);
      if (ok) {
        this.$message.success('水印已添加');
      } else {
        this.$message.warning(msg);
      }
    },

    // ── 工具 3：一键转 JPG ────────────────────────────────────
    async handleSaveAsJpg() {
      const folder = await selectFolderDialog('选择保存路径');
      if (!folder) return;
      const result = await cepInterface.evalExtendscript(`saveAsJpg("${encodeURIComponent(folder)}", "${encodeURIComponent('output')}")`);
      const { ok, msg } = this.parseJsxResult(result);
      if (ok) {
        this.$message.success(`已保存到：${folder}`);
      } else {
        this.$message.warning(msg);
      }
    },

    // ── 工具 4：尺寸规范化 ────────────────────────────────────
    handleResizeDocument() {
      this.resizeDialog.visible = true;
    },
    resetResizeDialog() {
      this.resizeDialog.width = '';
      this.resizeDialog.height = '';
      this.resizeDialog.activePreset = '';
    },
    applyResizePreset(p) {
      this.resizeDialog.width = String(p.w);
      this.resizeDialog.height = String(p.h);
      this.resizeDialog.activePreset = p.label;
    },
    async confirmResize() {
      const wStr = this.resizeDialog.width.trim();
      const hStr = this.resizeDialog.height.trim();
      const inputW = wStr ? parseInt(wStr, 10) : null;
      const inputH = hStr ? parseInt(hStr, 10) : null;

      if (!inputW && !inputH) {
        this.$message.warning('请至少输入宽度或高度');
        return;
      }
      if ((inputW !== null && (isNaN(inputW) || inputW <= 0)) || (inputH !== null && (isNaN(inputH) || inputH <= 0))) {
        this.$message.warning('请输入有效的正整数尺寸');
        return;
      }

      // 如果只填了一边，需要先从 PS 获取原始尺寸做等比计算
      let finalW = inputW;
      let finalH = inputH;
      if (!inputW || !inputH) {
        // 通过 JSX 获取当前文档尺寸
        const sizeResult = await cepInterface.evalExtendscript(
          'app.documents.length > 0 ? (app.activeDocument.width.as("px") + "," + app.activeDocument.height.as("px")) : "false:请先在 PS 中打开一个文档"'
        );
        if (sizeResult.startsWith('false:')) {
          this.$message.warning(sizeResult.slice(6));
          return;
        }
        const [origW, origH] = sizeResult.split(',').map(Number);
        const sized = this.calcProportionalSize(origW, origH, inputW, inputH);
        finalW = sized.w;
        finalH = sized.h;
      }

      this.resizeDialog.visible = false;
      const result = await cepInterface.evalExtendscript(`resizeDocument(${finalW}, ${finalH})`);
      const { ok, msg } = this.parseJsxResult(result);
      if (ok) {
        this.$message.success(`尺寸已调整为 ${finalW} × ${finalH} px`);
      } else {
        this.$message.warning(msg);
      }
    },

    // ── 工具 5：画布旋转 ──────────────────────────────────────
    handleRotateCanvas() {
      this.rotateDialog.visible = true;
    },
    resetRotateDialog() {
      this.rotateDialog.preset = '90';
      this.rotateDialog.customAngle = '';
    },
    async confirmRotate() {
      let angle;
      if (this.rotateDialog.preset === 'custom') {
        angle = parseFloat(this.rotateDialog.customAngle);
        if (isNaN(angle) || angle < -360 || angle > 360) {
          this.$message.warning('角度需在 -360 到 360 之间');
          return;
        }
      } else {
        angle = Number(this.rotateDialog.preset);
      }
      this.rotateDialog.visible = false;
      const result = await cepInterface.evalExtendscript(`rotateCanvas(${angle})`);
      const { ok, msg } = this.parseJsxResult(result);
      if (ok) {
        this.$message.success('画布旋转成功');
      } else {
        this.$message.warning(msg);
      }
    },

    // ── 工具 6：图片高清 ──────────────────────────────────────
    async handleEnhanceImage() {
      const result = await cepInterface.evalExtendscript('enhanceImageQuality()');
      const { ok, msg } = this.parseJsxResult(result);
      if (ok) {
        this.$message.success('图片高清处理完成');
      } else {
        this.$message.warning(msg);
      }
    },

    // ── 工具 101：一键样机替换 ────────────────────────────────
    handleMockupReplace() {
      if (!this.checkMember()) return;
      this.mockupDialog.visible = true;
    },
    resetMockupDialog() {
      this.mockupDialog.psdFolder = '';
      this.mockupDialog.materialFolder = '';
      this.mockupDialog.outputFolder = '';
    },
    async selectMockupPsdFolder() {
      const folder = await selectFolderDialog('选择样机文件夹（含 PSD 文件）');
      if (folder) this.mockupDialog.psdFolder = folder;
    },
    async selectMockupMaterialFolder() {
      const folder = await selectFolderDialog('选择素材文件夹（含图片文件）');
      if (folder) this.mockupDialog.materialFolder = folder;
    },
    async selectMockupOutputFolder() {
      const folder = await selectFolderDialog('选择输出文件夹');
      if (folder) this.mockupDialog.outputFolder = folder;
    },
    async confirmMockupReplace() {
      const { psdFolder, materialFolder, outputFolder } = this.mockupDialog;
      if (!psdFolder || !materialFolder || !outputFolder) {
        this.$message.warning('请选择样机文件夹、素材文件夹和输出文件夹');
        return;
      }

      const psdFiles = fs.readdirSync(psdFolder).filter((f) => f.toLowerCase().endsWith('.psd'));
      if (!psdFiles.length) {
        this.$message.warning('样机文件夹中没有找到 PSD 文件');
        return;
      }

      const imgExts = ['.jpg', '.jpeg', '.png', '.tif', '.tiff', '.bmp'];
      const materialFiles = fs.readdirSync(materialFolder).filter((f) => imgExts.includes(path.extname(f).toLowerCase()));
      if (!materialFiles.length) {
        this.$message.warning('素材文件夹中没有找到图片文件');
        return;
      }

      this.mockupDialog.visible = false;
      const total = psdFiles.length * materialFiles.length;
      this.progress = { visible: true, current: 0, total, errors: [] };
      let successCount = 0;

      for (let i = 0; i < materialFiles.length; i++) {
        const materialPath = path.join(materialFolder, materialFiles[i]).replace(/\\/g, '/');
        for (let j = 0; j < psdFiles.length; j++) {
          const psdPath = path.join(psdFolder, psdFiles[j]).replace(/\\/g, '/');
          const outputPath = path.join(outputFolder).replace(/\\/g, '/');
          try {
            const result = await cepInterface.evalExtendscript(`embedImageToMockup("${psdPath}", null, null, "${materialPath}", "${outputPath}")`);
            const { ok, msg } = this.parseJsxResult(result);
            if (ok) {
              successCount++;
            } else {
              this.progress.errors.push({ file: psdFiles[j], reason: msg });
            }
          } catch (e) {
            this.progress.errors.push({ file: psdFiles[j], reason: e.message });
          }
          this.progress.current = i * psdFiles.length + j + 1;
        }
      }

      this.progress.visible = false;
      const errCount = this.progress.errors.length;
      if (errCount === 0) {
        this.$message.success(`样机替换完成，共处理 ${successCount} 个文件`);
      } else {
        this.$message.warning(`完成 ${successCount} 个，失败 ${errCount} 个`);
      }
    },

    // ── 工具 102：批量导出图包 ────────────────────────────────
    handleBatchExport() {
      if (!this.checkMember()) return;
      this.exportDialog.visible = true;
    },
    resetExportDialog() {
      this.exportDialog.srcFolder = '';
      this.exportDialog.destFolder = '';
      this.exportDialog.sizesStr = '800,1500,2000';
    },
    async selectExportSrcFolder() {
      const folder = await selectFolderDialog('选择源文件夹');
      if (folder) this.exportDialog.srcFolder = folder;
    },
    async selectExportDestFolder() {
      const folder = await selectFolderDialog('选择目标文件夹');
      if (folder) this.exportDialog.destFolder = folder;
    },
    async confirmBatchExport() {
      const { srcFolder, destFolder, sizesStr } = this.exportDialog;
      if (!srcFolder || !destFolder) {
        this.$message.warning('请选择源文件夹和目标文件夹');
        return;
      }
      const sizes = sizesStr
        .split(',')
        .map((s) => parseInt(s.trim(), 10))
        .filter((n) => n > 0);
      if (!sizes.length) {
        this.$message.warning('请输入有效的导出尺寸');
        return;
      }

      const psdFiles = fs.readdirSync(srcFolder).filter((f) => f.toLowerCase().endsWith('.psd'));
      if (!psdFiles.length) {
        this.$message.warning('源文件夹中没有找到 PSD 文件');
        return;
      }

      this.exportDialog.visible = false;
      const total = psdFiles.length * sizes.length;
      this.progress = { visible: true, current: 0, total, errors: [] };
      let successCount = 0;

      for (let i = 0; i < psdFiles.length; i++) {
        const psdPath = path.join(srcFolder, psdFiles[i]).replace(/\\/g, '/');
        const baseName = psdFiles[i].replace(/\.[^.]+$/, '');
        for (let j = 0; j < sizes.length; j++) {
          const outName = this.buildExportFileName(baseName, sizes[j]);
          const destPath = path.join(destFolder, outName).replace(/\\/g, '/');
          try {
            const result = await cepInterface.evalExtendscript(
              `exportPsdAsPng("${encodeURIComponent(psdPath)}", "${encodeURIComponent(destPath)}", ${sizes[j]})`
            );
            const { ok, msg } = this.parseJsxResult(result);
            if (ok) {
              successCount++;
            } else {
              this.progress.errors.push({ file: outName, reason: msg });
            }
          } catch (e) {
            this.progress.errors.push({ file: outName, reason: e.message });
          }
          this.progress.current = i * sizes.length + j + 1;
        }
      }

      this.progress.visible = false;
      const errCount = this.progress.errors.length;
      if (errCount === 0) {
        this.$message.success(`导出完成，共 ${successCount} 个文件，保存至：${destFolder}`);
      } else {
        this.$message.warning(`完成 ${successCount} 个，失败 ${errCount} 个`);
      }
    },

    // ── 工具 103：批量智能重命名 ──────────────────────────────
    handleBatchRename() {
      if (!this.checkMember()) return;
      this.renameDialog.visible = true;
    },
    resetRenameDialog() {
      Object.assign(this.renameDialog, { folder: '', prefix: '', suffix: '', startIndex: 1, preview: [], files: [] });
    },
    async selectRenameFolder() {
      const folder = await selectFolderDialog('选择文件夹');
      if (folder) {
        this.renameDialog.folder = folder;
        this.renameDialog.preview = [];
        this.renameDialog.files = [];
      }
    },
    previewRename() {
      const { folder, prefix, suffix, startIndex } = this.renameDialog;
      if (!folder) {
        this.$message.warning('请先选择文件夹');
        return;
      }
      const files = fs.readdirSync(folder).filter((f) => {
        const stat = fs.statSync(path.join(folder, f));
        return stat.isFile();
      });
      if (!files.length) {
        this.$message.warning('所选文件夹中没有找到文件');
        return;
      }
      this.renameDialog.files = files;
      this.renameDialog.preview = files.map((f, i) => {
        const ext = path.extname(f);
        const newName = this.buildRenameFileName(prefix, startIndex + i, suffix, ext);
        return { old: f, newName };
      });
    },
    async confirmBatchRename() {
      const { folder, preview } = this.renameDialog;
      if (!preview.length) return;
      let successCount = 0;
      const errors = [];
      for (const item of preview) {
        try {
          fs.renameSync(path.join(folder, item.old), path.join(folder, item.newName));
          successCount++;
        } catch (e) {
          errors.push({ file: item.old, reason: e.message });
        }
      }
      this.renameDialog.visible = false;
      if (errors.length === 0) {
        this.$message.success(`重命名完成，共 ${successCount} 个文件`);
      } else {
        this.$message.warning(`完成 ${successCount} 个，失败 ${errors.length} 个：${errors.map((e) => e.file).join('、')}`);
      }
    },

    // ── 工具 104：光影自动匹配 ────────────────────────────────
    async handleLightingMatch() {
      if (!this.checkMember()) return;
      const result = await cepInterface.evalExtendscript('applyLightingAdjustment()');
      const { ok, msg } = this.parseJsxResult(result);
      if (ok) {
        this.$message.success('光影效果已应用');
      } else {
        this.$message.warning(msg);
      }
    }
  }
};
</script>

